record.field:
# Toggle maintenance status
current_status = env['ir.config_parameter'].sudo().get_param('maintenance.status', 'off')
new_status = 'off' if current_status == 'on' else 'on'

env['ir.config_parameter'].sudo().set_param('maintenance.status', new_status)

# Update times
current_time = fields.Datetime.now().isoformat()

if new_status == 'on':
    env['ir.config_parameter'].sudo().set_param('maintenance.start_time', current_time)
    # Calculate end time based on duration
    duration = env['ir.config_parameter'].sudo().get_param('maintenance.duration', '30 phút')
    try:
        end_time = None
        if 'phút' in duration.lower():
            minutes = int(''.join(filter(str.isdigit, duration)))
            end_time = fields.Datetime.now() + relativedelta(minutes=minutes)
        elif 'giờ' in duration.lower():
            hours = int(''.join(filter(str.isdigit, duration)))
            end_time = fields.Datetime.now() + relativedelta(hours=hours)
        elif 'ngày' in duration.lower():
            days = int(''.join(filter(str.isdigit, duration)))
            end_time = fields.Datetime.now() + relativedelta(days=days)

        if end_time:
            env['ir.config_parameter'].sudo().set_param('maintenance.end_time', end_time.isoformat())
    except:
        pass
else:
    env['ir.config_parameter'].sudo().set_param('maintenance.end_time', current_time)

# Show notification
action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': 'Thành công',
        'message': 'Đã chuyển chế độ bảo trì sang: %s' % new_status,
        'type': 'success',
        'sticky': False,
    }
}
